---
import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import { getResourcesPage, urlForImage } from '../lib/sanity';

const title = 'Resources | First Ithaca Chinese Christian Church';
const description =
  'Spiritual growth resources, reading plans, newcomer recommendations, and campus ministry connections at Cornell.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let resourcesPage: Awaited<ReturnType<typeof getResourcesPage>> = null;

try {
  resourcesPage = await getResourcesPage('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Fallback defaults (migrated from em.ficcc.org/resources) ----------
const fallbackCategories = [
  {
    title: 'Spiritual Growth',
    description:
      'Articles and guides to help you grow in your walk with Christ — whether you\'re exploring faith for the first time or have been following Jesus for years.',
    resources: [
      {
        title: 'What Does Baptism Mean and How Do I Get Baptized?',
        description:
          'An introduction to the meaning of baptism in the Christian faith and how to take this step at FICCC.',
        type: 'article' as const,
      },
      {
        title: 'Church Membership — Why It Matters',
        description:
          'Learn about the purpose and value of committing to a local church through membership.',
        type: 'article' as const,
      },
      {
        title: 'Keeping Your Faith in College',
        description:
          'Practical encouragement for college students navigating faith during their university years.',
        type: 'article' as const,
      },
      {
        title: 'Building Community as a Believer',
        description:
          'Why Christian community matters and how to find and foster it — especially in a college town like Ithaca.',
        type: 'article' as const,
      },
    ],
  },
  {
    title: 'Bible Readathon',
    description:
      'Join our community Bible reading plan. Download the reading plan and journey through Scripture together.',
    resources: [
      {
        title: 'Bible Readathon Reading Plan (PDF)',
        url: '/readathon4.pdf',
        description:
          'Download the Bible Readathon reading plan — a structured guide to reading through the Bible together as a church community.',
        type: 'pdf' as const,
      },
    ],
  },
  {
    title: 'Newcomer Recommendations',
    description:
      'Resources to help new believers and newcomers to our church get started on their spiritual journey.',
    resources: [
      {
        title: 'Newcomer Recommendations (PDF)',
        url: '/newcomer-recommendations.pdf',
        description:
          'A curated list of spiritual growth recommendations for anyone new to the Christian faith or to our church.',
        type: 'pdf' as const,
      },
    ],
  },
  {
    title: 'Cornell Campus Ministries',
    description:
      'FICCC is a registered student organization of Cornell University. Here are other campus ministries where you can connect with fellow believers.',
    resources: [
      {
        title: 'Cru (Campus Crusade for Christ)',
        url: 'https://www.crucornell.com',
        description: 'One of the largest interdenominational campus ministries at Cornell.',
        type: 'link' as const,
      },
      {
        title: 'Cornell Graduate Christian Fellowship (GCF)',
        url: 'https://www.cornellgcf.org',
        description: 'A community of graduate and professional students united by faith in Christ.',
        type: 'link' as const,
      },
      {
        title: 'InterVarsity Christian Fellowship',
        url: 'https://intervarsity.org',
        description: 'An evangelical campus ministry active at hundreds of universities, including Cornell.',
        type: 'link' as const,
      },
      {
        title: 'The Navigators',
        url: 'https://www.navigators.org/ministry/college/',
        description: 'A ministry focused on discipleship and life-on-life mentoring for college students.',
        type: 'link' as const,
      },
      {
        title: 'Asian American InterVarsity (AAIV)',
        url: 'https://intervarsity.org',
        description: 'A chapter of InterVarsity specifically welcoming Asian American students.',
        type: 'link' as const,
      },
      {
        title: 'Cornell Chinese Bible Study (CBS)',
        url: 'https://cornell.campusgroups.com',
        description: 'A bilingual Bible study group serving the Chinese-speaking community at Cornell.',
        type: 'link' as const,
      },
      {
        title: 'Korean Campus Crusade for Christ (KCCC)',
        url: 'https://www.crucornell.com',
        description: 'A ministry serving Korean and Korean American students at Cornell.',
        type: 'link' as const,
      },
    ],
  },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heroImage = resourcesPage?.heroImage
  ? urlForImage(resourcesPage.heroImage, { width: 1600 })
  : '/images/hero-placeholder.svg';
const heroTitle = resourcesPage?.heroTitle || 'Resources';
const heroSubtitle =
  resourcesPage?.heroSubtitle ||
  'Tools for spiritual growth, reading plans, and campus connections';

const categories =
  resourcesPage?.resourceCategories && resourcesPage.resourceCategories.length > 0
    ? resourcesPage.resourceCategories
    : fallbackCategories;

/** Return an icon label for the resource type badge. */
function typeLabel(type?: string): string {
  switch (type) {
    case 'pdf':
      return '↓ PDF';
    case 'link':
      return '↗ Link';
    default:
      return '📄 Article';
  }
}
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title={heroTitle}
      subtitle={heroSubtitle}
      backgroundImage={heroImage}
    />

    {categories.map((category, idx) => (
      <section
        class:list={['resource-section', { 'resource-section--alt': idx % 2 === 1 }]}
        aria-label={category.title}
      >
        <div class="resource-section__inner">
          <h2 class="section-heading">{category.title}</h2>
          {category.description && (
            <p class="resource-section__desc">{category.description}</p>
          )}

          {category.resources && category.resources.length > 0 && (
            <div class="resource-grid">
              {category.resources.map((resource) => (
                <div class="resource-card">
                  <div class="resource-card__header">
                    <span class:list={['resource-card__badge', `resource-card__badge--${resource.type || 'article'}`]}>
                      {typeLabel(resource.type)}
                    </span>
                  </div>
                  <h3 class="resource-card__title">
                    {resource.url ? (
                      <a
                        href={resource.url}
                        target={resource.type === 'link' ? '_blank' : undefined}
                        rel={resource.type === 'link' ? 'noopener noreferrer' : undefined}
                        download={resource.type === 'pdf' ? '' : undefined}
                      >
                        {resource.title}
                      </a>
                    ) : (
                      resource.title
                    )}
                  </h3>
                  {resource.description && (
                    <p class="resource-card__desc">{resource.description}</p>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </section>
    ))}
  </main>
</BaseLayout>

