    text-align: center;
    max-width: 40rem;
    margin-inline: auto;
    margin-block-end: var(--space-10);
  }

  /* ---------- Resource Grid ---------- */
  .resource-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(18rem, 1fr));
    gap: var(--space-6);
  }

  /* ---------- Resource Card ---------- */
  .resource-card {
    background-color: var(--color-bg);
