    background-color: #fff;
  }

  .resource-card:hover {
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  }

  .resource-card__header {
    display: flex;
    align-items: center;
  }

  .resource-card__badge {
    font-family: var(--font-body);
    font-size: var(--text-xs, 0.75rem);
    font-weight: 600;
